// ============================================
// VALIDAÇÃO E NORMALIZAÇÃO DE DADOS
// ============================================

const items = $input.all();
const validatedItems = [];

for (const item of items) {
  let data;

  // Verifica se 'item.json.body' existe E se é um objeto com dados
  if (item.json.body && Object.keys(item.json.body).length > 0) {
    // Se sim, usa o objeto 'body' (como no seu caso atual)
    data = item.json.body;
  } else {
    // Senão, usa o objeto 'json' principal (o formato antigo)
    data = item.json;
  }

  // ============================================
  // 1. VALIDAÇÃO MÍNIMA OBRIGATÓRIA
  // ============================================

  // Validar nome
  if (!data.name && !data.fullName && !data.full_name) {
    throw new Error('Campo "name" é obrigatório');
  }
  // Validar contato (email OU telefone)
  if (!data.email && !data.phone && !data.phoneNumber && !data.phone_number) {
    throw new Error('Email ou telefone é obrigatório');
  }

  // ============================================
  // 2. NORMALIZAÇÃO DE DADOS
  // ============================================

  // Normalizar telefone
  function normalizePhone(phone) {
    if (!phone) return null;

    // Remove tudo exceto números
    const cleaned = phone.toString().replace(/\D/g, '');

    // Adiciona código do país se não tiver
    if (cleaned.length === 11 && !cleaned.startsWith('55')) {
      return '+55' + cleaned;
    }

    if (cleaned.length === 10 && !cleaned.startsWith('55')) {
      return '+55' + cleaned;
    }

    if (!cleaned.startsWith('+')) {
      return '+' + cleaned;
    }

    return '+' + cleaned;
  }

  // Construir tags
  function buildTags(data) {
    const tags = {};

    // Tags de interesse
    if (data.interest || data.interesse) {
      tags.interesse = data.interest || data.interesse;
    }

    // Tags de origem
    if (data.utm_source) {
      tags.canal = data.utm_source;
    }

    // Tags de urgência
    if (data.urgency || data.urgencia) {
      tags.urgencia = data.urgency || data.urgencia;
    }

    // Tags customizadas
    if (data.tags && typeof data.tags === 'object') {
      Object.assign(tags, data.tags);
    }

    // Meta tags
    tags.created_via_webhook = true;
    tags.webhook_timestamp = new Date().toISOString();

    return tags;
  }

  // ============================================
  // 3. OBJETO NORMALIZADO
  // ============================================

  const leadId = $execution.id + '-' + Date.now(); // Temporário, será UUID no DB

  const normalized = {
    // Identificação
    leadId: leadId,

    // Dados pessoais (normalizar variações)
    fullName: (data.fullName || data.full_name || data.name || '').trim(),
    email: (data.email || '').toLowerCase().trim() || null,
    phoneNumber: normalizePhone(data.phoneNumber || data.phone_number || data.phone || data.telefone),

    // Origem e rastreamento
    source: data.source || data.origem || 'Webhook Direto',
    utmSource: data.utm_source || data.utmSource,
    utmMedium: data.utm_medium || data.utmMedium,
    utmCampaign: data.utm_campaign || data.utmCampaign,
    landingPage: data.landing_page || data.landingPage || data.page_url,

    // Metadados
    tags: buildTags(data),
    customFields: data.customFields || data.custom_fields || {}
  };

  validatedItems.push({ json: normalized });
}

return validatedItems;

// Resultado bruto do "Validar e Normalizar"
const leadData = $('Validar e Normalizar').item.json;

// Resultado bruto do "Buscar Config Origem"
const origemConfig = $input.item.json;

// Retorno SEM processamento
return {
    json: {
        ...leadData,
        routing_metadata: origemConfig
    }
};

